import React, { useState } from "react";

/*
  TechnicianLayout.jsx
  ----------------------------------------------------
  Permanent layout shell for Technician users.

  PURPOSE:
  - Technicians investigate assigned systems
  - Validate AI findings
  - Upload evidence / logs
  - NO financial approvals
  - NO replacement decisions

  RULES:
  - Layout shell only
  - Child pages rendered inside main content area
  - No routing logic
  - No API calls
  - Dummy data only
*/

// --------------------------------------------------
// Dummy Technician Context (replace with auth later)
// --------------------------------------------------
const TECHNICIAN = {
  name: "A. Kumar",
  role: "Field Technician",
  shiftStatus: "Active", // Active | Offline
};

// --------------------------------------------------
// Sidebar Navigation Config
// --------------------------------------------------
const NAV_ITEMS = [
  {
    id: "dashboard",
    label: "Technician Dashboard",
    icon: "🧭",
    pending: 2,
  },
  {
    id: "assigned",
    label: "Assigned Systems",
    icon: "🖥️",
    pending: 5,
  },
  {
    id: "logs",
    label: "Investigation Logs",
    icon: "📋",
    pending: 1,
  },
];

// --------------------------------------------------
// Component
// --------------------------------------------------
export default function TechnicianLayout({ children }) {
  const [activeNav, setActiveNav] = useState("dashboard");

  return (
    <div className="h-screen flex bg-gray-50 text-slate-800">

      {/* ==================================================
          LEFT SIDEBAR
         ================================================== */}
      <aside className="w-64 bg-slate-900 text-slate-100 flex flex-col fixed inset-y-0">
        {/* Logo */}
        <div className="px-6 py-5 border-b border-slate-700">
          <div className="text-lg font-semibold tracking-wide">
            MaintAI
          </div>
          <div className="text-xs text-slate-400 mt-1">
            Technician Console
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 px-3 py-4 space-y-1">
          {NAV_ITEMS.map((item) => {
            const active = activeNav === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setActiveNav(item.id)}
                className={`w-full flex items-center justify-between px-3 py-2 rounded-md text-sm
                  ${active
                    ? "bg-slate-800 text-white"
                    : "text-slate-300 hover:bg-slate-800 hover:text-white"
                  }`}
              >
                <div className="flex items-center gap-3">
                  <span className="text-base">{item.icon}</span>
                  <span>{item.label}</span>
                </div>

                {item.pending > 0 && (
                  <span className="text-xs bg-sky-600 text-white px-2 py-0.5 rounded-full">
                    {item.pending}
                  </span>
                )}
              </button>
            );
          })}
        </nav>

        {/* Sidebar Footer */}
        <div className="px-4 py-3 border-t border-slate-700 text-xs text-slate-400">
          Logged in as Technician
        </div>
      </aside>

      {/* ==================================================
          RIGHT SIDE (HEADER + CONTENT + FOOTER)
         ================================================== */}
      <div className="flex-1 ml-64 flex flex-col">

        {/* ================= HEADER ================= */}
        <header className="h-14 bg-white border-b flex items-center justify-between px-6">
          {/* Search */}
          <div className="flex items-center gap-3">
            <input
              type="text"
              placeholder="Search system ID..."
              className="px-3 py-1.5 border rounded-md text-sm w-64 bg-gray-50"
            />
          </div>

          {/* Right controls */}
          <div className="flex items-center gap-4">
            {/* Notifications */}
            <button className="relative text-slate-600 hover:text-slate-800">
              🔔
              <span className="absolute -top-1 -right-1 h-2 w-2 bg-red-500 rounded-full" />
            </button>

            {/* Technician Info */}
            <div className="flex items-center gap-3">
              <div className="text-right">
                <div className="text-sm font-medium">{TECHNICIAN.name}</div>
                <div className="text-xs text-slate-500">{TECHNICIAN.role}</div>
              </div>

              {/* Avatar */}
              <div className="h-9 w-9 rounded-full bg-slate-200 flex items-center justify-center text-sm font-semibold">
                AK
              </div>

              {/* Shift Status */}
              <span
                className={`text-xs px-2 py-0.5 rounded-full
                  ${TECHNICIAN.shiftStatus === "Active"
                    ? "bg-green-50 text-green-700"
                    : "bg-gray-100 text-gray-600"
                  }`}
              >
                {TECHNICIAN.shiftStatus}
              </span>
            </div>
          </div>
        </header>

        {/* ================= MAIN CONTENT ================= */}
        <main className="flex-1 overflow-y-auto">
          <div className="max-w-7xl mx-auto px-6 py-6">
            {/* 
              Child pages render here.
              Example:
              - Technician Dashboard
              - Assigned Systems
              - Investigation Logs
            */}
            {children || (
              <div className="text-slate-500 text-sm">
                Select a section from the sidebar to begin.
              </div>
            )}
          </div>
        </main>

        {/* ================= FOOTER ================= */}
        <footer className="h-10 border-t bg-white flex items-center justify-between px-6 text-xs text-slate-500">
          <div className="flex items-center gap-4">
            <span>
              Agent Status: <span className="text-green-600">Connected</span>
            </span>
            <span>Version 1.4.2</span>
          </div>

          <div>
            <span className="px-2 py-0.5 bg-slate-100 rounded-md">
              Production
            </span>
          </div>
        </footer>
      </div>
    </div>
  );
}
